def gen(rng, size):
    m = max(1, min(size, 50))
    vals = rng.sample(range(1, 101), m)
    def construct(a):
        if not a:
            return None
        i = a.index(max(a))
        return ('n', a[i], construct(a[:i]), construct(a[i+1:]))
    def serialize(node):
        if node is None:
            return []
        out = []
        q = [node]
        while q:
            cur = q.pop(0)
            if cur is None:
                out.append(None)
                continue
            out.append(cur[1])
            q.append(cur[2])
            q.append(cur[3])
        while out and out[-1] is None:
            out.pop()
        return out
    tree = construct(vals)
    arr = serialize(tree)
    remaining = [v for v in range(1, 101) if v not in vals]
    val = rng.choice(remaining)
    return [arr, val]

