class Solution:
    def insertIntoMaxTree(self, root, val):
        if root is None or val > root.val:
            node = TreeNode(val)
            node.left = root
            return node
        cur = root
        while cur.right is not None and cur.right.val > val:
            cur = cur.right
        node = TreeNode(val)
        node.left = cur.right
        cur.right = node
        return root

