        const node = new TreeNode(val);
        node.left = root;
        return node;
    }
    let cur = root;
    while (cur.right !== null && cur.right.val > val) {
        cur = cur.right;
    }
    const node = new TreeNode(val);
    node.left = cur.right;
    cur.right = node;
    return root;
